    value = fields.String()

    @validates('value')
    def validate_value(self, value):
        if value == 'invalid':
            raise ValidationError('Value cannot be "invalid"')
        return value


class Foo(Schema):
    bar = fields.Nested(Bar)
    baz = fields.String()

    @validates('baz')
    def validate_baz(self, value):
        if value == 'wrong':
            raise ValidationError('Baz cannot be "wrong"')
        return value


